testbench:
`timescale 1ns / 1ps

module instr_reg_tb;

reg clk;
reg rst;
reg [1:0] fetch;
reg [7:0] data;

wire [2:0] ins;
wire [4:0] ad1;
wire [7:0] ad2;

instr_reg uut (
    .clk(clk),
    .rst(rst),
    .fetch(fetch),
    .data(data),
    .ins(ins),
    .ad1(ad1),
    .ad2(ad2)
);

integer error;
integer expected_ins;
integer expected_ad1;
integer expected_ad2;

initial begin
    // Initialize Inputs
    clk = 0;
    rst = 0;
    fetch = 2'b00;
    data = 8'h00;
    error = 0;

    // Wait 100 ns for initialization
    #100;

    // De-assert reset
    rst = 1;
    #10;

    // Perform fetch operation 1 from register
    fetch = 2'b01;
    #5;
    data = 8'b01011100;
    expected_ins = 3'b010;
    expected_ad1 = 5'b11100;
    expected_ad2 = 8'b00;
    #20;

    // Check the values
    if (ins !== expected_ins) begin
        error = error + 1; 
        $display("Failed at fetch operation 1: clk=%d, ins=%b (expected %d)", clk, ins, expected_ins);
    end

    if (ad1 !== expected_ad1) begin
        error = error + 1; 
        $display("Failed at fetch operation 1: clk=%d, ad1=%b (expected %d)", clk, ad1, expected_ad1);
    end

    if (ad2 !== expected_ad2) begin
        error = error + 1; 
        $display("Failed at fetch operation 1: clk=%d, ad2=%b (expected %d)", clk, ad2, expected_ad2);
    end

    // Additional test cases can be added here

    // Finish simulation and display total errors
    if (error == 0) begin
            $display("=========== Your Design Passed ===========");
            end
    else begin
        $display("=========== Test completed with %d failures ===========", error);
    end
    $finish;
end

always #5 clk = ~clk;

endmodule

reference_rtl:
module instr_reg (
    input clk,
    input rst,
    input [1:0] fetch,
    input [7:0] data,
    output [2:0] ins,
    output [4:0] ad1,
    output [7:0] ad2
);

    reg [7:0] ins_p1, ins_p2;
    reg [2:0] state;

    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            ins_p1 <= 8'd0;
            ins_p2 <= 8'd0;
        end else begin
            if (fetch == 2'b01) begin // Fetch operation 1, from REG
                ins_p1 <= data;
                ins_p2 <= ins_p2;
            end else if (fetch == 2'b10) begin // Fetch operation 2, from RAM/ROM
                ins_p1 <= ins_p1;
                ins_p2 <= data;
            end else begin
                ins_p1 <= ins_p1;
                ins_p2 <= ins_p2;
            end
        end
    end

    assign ins = ins_p1[7:5]; // High 3 bits, instructions
    assign ad1 = ins_p1[4:0];  // Low 5 bits, register address
    assign ad2 = ins_p2;
endmodule
